def draw_path(ax, path, color):
    if not path:  return
    xs = [nodes_x[i] for i in path]
    ys = [nodes_y[i] for i in path]
    ax.plot(xs, ys, color=color, linewidth=2.2, zorder=10)
    ax. scatter(xs, ys, color=color, s=30, zorder=11)

